import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

// Seeded PRNG so the heatmap is identical on every load (stable snapshots).
var __seed = 0x66f70829
function rand() {
  __seed |= 0
  __seed = (__seed + 0x6d2b79f5) | 0
  var t = Math.imul(__seed ^ (__seed >>> 15), 1 | __seed)
  t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t
  return ((t ^ (t >>> 14)) >>> 0) / 4294967296
}

function generateData(count, yrange) {
  var i = 0
  var series = []
  while (i < count) {
    var x = (i + 1).toString()
    var y = Math.floor(rand() * (yrange.max - yrange.min + 1)) + yrange.min

    series.push({
      x: x,
      y: y,
    })
    i++
  }
  return series
}

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        name: 'Auth',
        data: generateData(20, {
          min: 0,
          max: 90,
        }),
      },
      {
        name: 'API',
        data: generateData(20, {
          min: 0,
          max: 90,
        }),
      },
      {
        name: 'UI',
        data: generateData(20, {
          min: 0,
          max: 90,
        }),
      },
      {
        name: 'Database',
        data: generateData(20, {
          min: 0,
          max: 90,
        }),
      },
      {
        name: 'Cache',
        data: generateData(20, {
          min: 0,
          max: 90,
        }),
      },
      {
        name: 'Search',
        data: generateData(20, {
          min: 0,
          max: 90,
        }),
      },
      {
        name: 'Payments',
        data: generateData(20, {
          min: 0,
          max: 90,
        }),
      },
      {
        name: 'Email',
        data: generateData(20, {
          min: 0,
          max: 90,
        }),
      },
      {
